import React, { useEffect, useState } from "react";
import { CCol, CFormCheck, CFormLabel, CRow, CButton } from '@coreui/react';
import { useParams } from "react-router-dom";
import { getApplicantDataById, updateApplicantData } from "src/components/services/CareerApi";
import Linkify from "react-linkify";
import { download_file, epochTogmt } from "src/utils/Common";
import TextArea from "src/utils/TextArea";
import authService from "src/auth/auth.service";
import GoBackComponent from "src/utils/GoBackComponent";
import StatusDrop from "src/utils/StatusDrop";
import { v4 as uuidv4 } from 'uuid';

const ApplicantDEtails = () => {
    const { id } = useParams();
    const [userData] = useState(authService.getUserDetailsFromLocalStorage())
    const [applicantData, setApplicantData] = useState({});
    const [reason, setReason] = useState();
    const [errors, setErrors] = useState({});

    const getApplicantDetails = async () => {
        let response = await getApplicantDataById(id);
        if (response?.code === 200) {
            setApplicantData(response?.results);
        }
    }

    const editReason = () => {
        setReason(applicantData?.reason)
    }

    const handleChange = (event) => {
        setReason(event.target.value.trimStart())
    }

    const validateForm = () => {
        let errors = {};
        let formIsValid = true;
        if (!reason) {
            errors['reason'] = "Please enter reason";
            formIsValid = false;
        }
        setErrors(errors);
        setTimeout(() => {
            setErrors({});
        }, 2000);
        return formIsValid;
    }

    const handleSubmit = async (event) => {
        event.preventDefault();
        if (validateForm()) {
            let postData = {
                id: id,
                reason: reason
            }
            let response = await updateApplicantData(postData);
            if (response?.code === 202) {
                setApplicantData((applicantData) => ({ ...applicantData, reason: reason }));
                setReason("");
            }
        }
    };

    useEffect(() => {
        getApplicantDetails();
    }, [])

    return (
        <>
            <GoBackComponent goBackData={"career/applicant"} />
            <div className='customContainer'>
                <div className='form-group'>
                    <CRow>
                        <CCol md={4}>
                            <div className='form-group'>
                                <CFormLabel htmlFor="exampleFormControlTextarea1">Status:</CFormLabel>
                                <div className='form-control' style={{ height: 'auto' }}>{applicantData?.status}</div>
                            </div>
                        </CCol>
                        <CCol md={8}>
                            <CFormLabel htmlFor='exampleFormControlTextarea1'>
                                Action
                            </CFormLabel>
                            <CRow>
                                <CCol md={6}>
                                    <StatusDrop
                                        id={applicantData.id}
                                        status={applicantData.status}
                                        type={'APPLICANT'}
                                        action={getApplicantDetails}
                                        key={uuidv4()}
                                        publishPermission={""}
                                    />
                                </CCol>
                            </CRow>
                        </CCol>
                    </CRow>
                </div>
                <CRow>
                    <CCol md={4}>
                        <div className='form-group'>
                            <CFormLabel htmlFor="exampleFormControlTextarea1">First Name:</CFormLabel>
                            <div className='form-control' style={{ height: 'auto' }}>{applicantData?.firstName}</div>
                        </div>
                    </CCol>
                    <CCol md={4}>
                        <div className='form-group'>
                            <CFormLabel htmlFor="exampleFormControlTextarea1">Last Name:</CFormLabel>
                            <div className='form-control' style={{ height: 'auto' }}>{applicantData?.lastName}</div>
                        </div>
                    </CCol>
                    <CCol md={4}>
                        <div className='form-group'>
                            <CFormLabel htmlFor="exampleFormControlTextarea1">Email:</CFormLabel>
                            <div className='form-control' style={{ height: 'auto' }}>{applicantData?.email}</div>
                        </div>
                    </CCol>
                    <CCol md={4}>
                        <div className='form-group'>
                            <CFormLabel htmlFor="exampleFormControlTextarea1">Country Code:</CFormLabel>
                            <div className='form-control' style={{ height: 'auto' }}>{applicantData?.countryCode}</div>
                        </div>
                    </CCol>
                    <CCol md={4}>
                        <div className='form-group'>
                            <CFormLabel htmlFor="exampleFormControlTextarea1">Phone No:</CFormLabel>
                            <div className='form-control' style={{ height: 'auto' }}>{applicantData?.phone}</div>
                        </div>
                    </CCol>

                    {applicantData?.link &&
                        <CCol md={12}>
                            <div className='form-group'>
                                <CFormLabel htmlFor="exampleFormControlTextarea1">Portfolio Link:</CFormLabel>
                                <div className='form-control' style={{ height: 'auto' }}>
                                    <Linkify componentDecorator={(decoratedHref, decoratedText, key) => (
                                        <a target="blank" href={decoratedHref} key={key}>
                                            {decoratedText}
                                        </a>
                                    )}>
                                        {applicantData?.link ? applicantData?.link : ""}
                                    </Linkify>
                                </div>
                            </div>
                        </CCol>
                    }
                </CRow>

                <hr className='my-4' />

                <CRow>
                    <CCol md={12}>
                        <div className='form-group'>
                            <CFormLabel htmlFor="exampleFormControlTextarea1">Description:</CFormLabel>
                            <div className='form-control' style={{ height: 'auto', minHeight: '40px' }}>
                                <Linkify componentDecorator={(decoratedHref, decoratedText, key) => (
                                    <a target="blank" href={decoratedHref} key={key}>
                                        {decoratedText}
                                    </a>
                                )}>
                                    {applicantData?.description ? applicantData?.description : ""}
                                </Linkify>
                            </div>
                        </div>
                    </CCol>

                </CRow>

                <hr className='my-4' />

                <CRow>
                    <CCol md={4}>
                        <div className='form-group'>
                            <CFormLabel htmlFor="exampleFormControlTextarea1">Position Name:</CFormLabel>
                            <div className='form-control' style={{ height: 'auto' }}>{applicantData?.position}</div>
                        </div>
                    </CCol>
                    <CCol md={4}>
                        <div className='form-group'>
                            <CFormLabel htmlFor="exampleFormControlTextarea1">Position Type:</CFormLabel>
                            <div className='form-control' style={{ height: 'auto' }}>{applicantData?.jobType === "FULL_TIME" ? "Full Time" : "Intern"}</div>
                        </div>
                    </CCol>
                    {applicantData?.createTime &&
                        <CCol md={4}>
                            <div className='form-group'>
                                <CFormLabel htmlFor="exampleFormControlTextarea1">Applied Date:</CFormLabel>
                                <div className='form-control' style={{ height: 'auto' }}>{epochTogmt(applicantData?.createTime)}</div>
                            </div>
                        </CCol>
                    }
                    {applicantData?.reason &&
                        <CCol md={12}>
                            <div className='form-group'>
                                <CFormLabel htmlFor="exampleFormControlTextarea1">Reason:
                                    {!reason && userData.email === "punam@wsegroup.in" && <a href="javascript:void(0)" onClick={() => editReason()}> Edit</a>}
                                </CFormLabel>
                                {!reason ?
                                    <div className='form-control' style={{ height: 'auto', minHeight: '100px' }}>{applicantData?.reason}</div> :
                                    <>
                                        <TextArea
                                            value={reason}
                                            name={"name"}
                                            onChange={handleChange}
                                            error={errors['reason']}
                                        />
                                        <CButton type="submit" color="primary" className="mb-3" style={{ float: "right" }} onClick={handleSubmit}>
                                            {"Update"}
                                        </CButton>
                                    </>
                                }
                            </div>
                        </CCol>
                    }
                </CRow>

                <div className='form-control' style={{ height: 'auto' }}>
                    <CFormLabel htmlFor="exampleFormControlTextarea1">Resume:</CFormLabel>
                    <div class="d-flex flex-wrap">
                        {applicantData?.resume?.imageUrl &&
                            <div class={applicantData?.resume?.attachmentType == "PDF" || applicantData?.resume?.attachmentType == "DOCUMENT" ? "previewPan ico" : "previewPan"}>
                                <span>
                                    <a href={"javascript:void(0)"} onClick={(e) => download_file(e, applicantData?.resume?.imageUrl)} target="_blank" rel="noopener noreferrer">
                                        <img src={applicantData?.resume?.attachmentType == "PDF" ? "https://cdn.wseinfratech.com/pdf_icon.svg" : "https://cdn.wseinfratech.com/word_icon.svg"} className='img-fluid' />
                                    </a>
                                </span>
                            </div>
                        }
                    </div>
                </div>
            </div>
        </>
    )
}

export default ApplicantDEtails;
